class Solution:
    def numSquares(self, n):
        # Independent BFS over reachable remainders: level number is the count
        # of squares used to reach zero.
        squares = []
        i = 1
        while i * i <= n:
            squares.append(i * i)
            i += 1
        from collections import deque
        visited = [False] * (n + 1)
        q = deque([(n, 0)])
        visited[n] = True
        while q:
            rem, steps = q.popleft()
            if rem == 0:
                return steps
            for s in squares:
                if s > rem:
                    break
                nxt = rem - s
                if not visited[nxt]:
                    visited[nxt] = True
                    q.append((nxt, steps + 1))
        return 0

